class Solution {
public:
   bool flip_and_count(int n) { 
       int ans = 0; 
       while (n) { 
           ans += n & 1; 
           n >>= 1; 
       } 
       return ans; 
   } 
};

int main() {
    int n;
    cin >> n;
    int arr[n];
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    cout << Solution().flip_and_count(max(arr) ^ max(abs(x) for x in arr)) << endl;
    return 0;
}
